import { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import { ChevronDown, ChevronRight } from "lucide-react";

const Sidebar = () => {
  const [adminOpen, setAdminOpen] = useState(true);
  const [examOpen, setExamOpen] = useState(true);
  const location = useLocation();

  const isActive = (path) => location.pathname === path;

  return (
    <div className="w-64 h-screen bg-gray-900 text-white flex flex-col">

      {/* Header */}
      <div className="p-4 border-b border-gray-700">
        <h2 className="text-xl font-bold">Admin Panel</h2>
      </div>

      {/* Menu */}
      <div className="flex-1 p-4">

        {/* Admin Controller */}
        <button
          onClick={() => setAdminOpen(!adminOpen)}
          className="flex justify-between items-center w-full py-2 font-semibold hover:text-blue-400"
        >
          <span>Admin Controller</span>
          {adminOpen ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
        </button>

        {adminOpen && (
          <div className="ml-4 mt-2">

            {/* Exam Menu */}
            <button
              onClick={() => setExamOpen(!examOpen)}
              className="flex justify-between items-center w-full py-2 hover:text-blue-400"
            >
              <span>Exam</span>
              {examOpen ? (
                <ChevronDown size={16} />
              ) : (
                <ChevronRight size={16} />
              )}
            </button>

            {/* Exam Master Link */}
            {examOpen && (
              <div className="ml-4 mt-2">
                <Link
                  to="/dashboard/exam-master"
                  className={`block py-2 px-3 rounded ${
                    isActive("/dashboard/exam-master")
                      ? "bg-blue-600"
                      : "hover:bg-gray-700"
                  }`}
                >
                  Exam Master
                </Link>
              </div>
            )}

          </div>
        )}
      </div>
    </div>
  );
};

export default Sidebar;
